const body = $input.first().json.body || $input.first().json;
const profile_id = body.profile_id;
const place_ids = Array.isArray(body.place_ids) ? body.place_ids : [];
const channel = body.channel || 'email';
const tone = body.tone || 'professional';

if (!profile_id) throw new Error('profile_id is required.');

const validChannels = ['email', 'linkedin', 'whatsapp'];
const validTones = ['professional', 'conversational', 'direct'];
if (!validChannels.includes(channel)) throw new Error('channel must be: email, linkedin, or whatsapp');
if (!validTones.includes(tone)) throw new Error('tone must be: professional, conversational, or direct');

return [{ json: { profile_id, place_ids, channel, tone } }];

const params = $('Validate Inputs').first().json;
const profileData = $('Get Sender Profile').first().json;
const profileObj = Array.isArray(profileData) ? profileData[0] : profileData;

if (!profileObj || !profileObj.id) {
  throw new Error('Sender profile not found. Check that profile_id exists in the sender_profiles table.');
}

// n8n auto-splits Supabase array responses into individual items — use $input.all()
const leads = $input.all().map(function(item) { return item.json; });

if (leads.length === 0) {
  throw new Error('No leads found. Run scrape + enrich first, or check the place_ids provided.');
}

return leads.map(function(lead) {
  return {
    json: {
      lead: lead,
      profile: profileObj,
      channel: params.channel,
      tone: params.tone,
      profile_id: params.profile_id
    }
  };
});

// runOnceForAllItems (default) — iterate all leads and build prompts
return $input.all().map(function(inputItem) {
  var item = inputItem.json;
  var lead = item.lead;
  var profile = item.profile;
  var channel = item.channel;
  var tone = item.tone;

  var toneDesc = {
    professional: 'formal, respectful, business-appropriate',
    conversational: 'friendly, warm, approachable yet professional',
    direct: 'concise, confident, gets to the point quickly'
  };
  var toneText = toneDesc[tone] || toneDesc.professional;

  var channelGuide;
  if (channel === 'linkedin') {
    channelGuide = 'Generate LinkedIn outreach.\nRules:\n- subject_line: empty string \"\"\n- message_body: LinkedIn message, max 1000 characters, ' + toneText + '\n- linkedin_connection_note: connection request note, max 300 characters, human and casual';
  } else if (channel === 'whatsapp') {
    channelGuide = 'Generate a WhatsApp message.\nRules:\n- subject_line: empty string \"\"\n- message_body: max 280 characters, ' + toneText + ', friendly and direct\n- linkedin_connection_note: empty string \"\"';
  } else {
    channelGuide = 'Generate a cold email.\nRules:\n- subject_line: 6-10 words, specific to this business, not salesy\n- message_body: 100-200 words, ' + toneText + '\n- linkedin_connection_note: empty string \"\"';
  }

  var parts = [
    'Business: ' + lead.business_name,
    lead.category ? 'Type: ' + lead.category : null,
    (lead.city || lead.state) ? 'Location: ' + [lead.city, lead.state].filter(Boolean).join(', ') : null,
    lead.google_rating ? 'Google rating: ' + lead.google_rating + ' stars (' + (lead.review_count || 0) + ' reviews)' : null,
    lead.maps_description ? 'About (Google): ' + String(lead.maps_description).slice(0, 300) : null,
    lead.website ? 'Website: ' + lead.website : 'Website: none',
    lead.email ? 'Email: ' + lead.email : null,
    lead.website_phone ? 'Phone: ' + lead.website_phone : (lead.phone ? 'Phone (Google): ' + lead.phone : null),
    lead.owner_name ? 'Owner/contact: ' + lead.owner_name : null,
    lead.company_description ? 'Company: ' + String(lead.company_description).slice(0, 300) : null
  ].filter(Boolean);

  var leadContext = parts.join('\n');
  var systemPrompt = 'You are a B2B outreach specialist. Write personalized, genuine messages that sound human, not AI-generated spam. Focus on value for the prospect. Never make up facts. Respond only with valid JSON.';

  var userPrompt = 'SENDER:\n';
  userPrompt += 'Name: ' + profile.owner_name + '\n';
  userPrompt += 'Company: ' + profile.company_name + '\n';
  userPrompt += 'What we do: ' + profile.service_description + '\n';
  if (profile.value_proposition) userPrompt += 'Why us: ' + profile.value_proposition + '\n';
  if (profile.target_industry) userPrompt += 'We focus on: ' + profile.target_industry + '\n';
  var INDUSTRY_PAIN_POINTS = {'property management':'chasing late rent, handling maintenance requests at odd hours, coordinating between owners and tenants, lease renewals, and tenant screening','property':'chasing late rent, handling maintenance requests, coordinating between property owners and tenants, and managing lease renewals','dental':'appointment no-shows, patient recall campaigns, insurance claim follow-ups, and attracting new patients','auto repair':'appointment scheduling gaps, service reminder follow-ups, estimate approvals, and keeping repeat customers coming back','restaurant':'reservation and walk-in management, online ordering setup, customer loyalty, and handling reviews','real estate':'slow lead follow-up, listing management, client communication volume, and scheduling showings','healthcare':'patient scheduling, appointment reminders, follow-up care coordination, and insurance verification','legal':'client intake bottlenecks, document collection, deadline tracking, and billing follow-ups','accounting':'chasing documents from clients, tax deadline reminders, year-round client communication, and new client onboarding','cleaning':'recurring booking management, staff scheduling, quality control follow-ups, and reducing customer churn','landscaping':'seasonal job scheduling, quote follow-ups, recurring service reminders, and crew coordination','salon':'appointment reminders, no-show reduction, rebooking follow-ups, and building client loyalty','fitness':'membership renewal reminders, class booking management, personal training follow-ups, and lead nurturing'};
  if (profile.target_industry) { var ind = profile.target_industry.toLowerCase(); var painPoints = null; for (var key in INDUSTRY_PAIN_POINTS) { if (ind.indexOf(key) >= 0 || key.indexOf(ind) >= 0) { painPoints = INDUSTRY_PAIN_POINTS[key]; break; } } if (painPoints) userPrompt += 'Industry pain points (reference naturally if they fit): ' + painPoints + '\n'; }
  userPrompt += '\nTARGET:\n' + leadContext;
  userPrompt += '\n\nTASK: ' + channelGuide;
  userPrompt += '\n\nRULES:\n- Use owner name if available, otherwise use "Hi [Business Name] team"\n- Reference specific details naturally where relevant\n- Avoid: "I hope this finds you well", "I came across your business", generic filler\n- Sound like a real person reaching out, not a mass campaign';
  userPrompt += '\n\nReturn ONLY this JSON (no markdown, no other text):\n{\n  "subject_line": "",\n  "message_body": "",\n  "linkedin_connection_note": "",\n  "personalization_score": 3,\n  "personalization_notes": ""\n}';

  return { json: { lead: lead, profile: profile, channel: channel, tone: tone, profile_id: item.profile_id, prompt: { system: systemPrompt, user: userPrompt } } };
});

// runOnceForAllItems — process all Groq responses, zip with Build LLM Prompt data by index
var allGroqResponses = $input.all();
var allBuildData = $('Build LLM Prompt').all();

return allGroqResponses.map(function(groqItem, index) {
  var groqResponse = groqItem.json;
  var buildData = allBuildData[index] ? allBuildData[index].json : {};
  var lead = buildData.lead || {};

  var parsed = null;
  var modelUsed = 'failed';

  if (groqResponse.choices && groqResponse.choices[0] && groqResponse.choices[0].message) {
    try {
      parsed = JSON.parse(groqResponse.choices[0].message.content);
      modelUsed = 'groq-llama3.3-70b';
    } catch(e) {}
  }

  if (!parsed) {
    parsed = {
      subject_line: '',
      message_body: '[Generation failed - check YOUR_GROQ_API_KEY and retry]',
      linkedin_connection_note: '',
      personalization_score: 1,
      personalization_notes: 'LLM call failed'
    };
  }

  parsed.subject_line = String(parsed.subject_line || '').slice(0, 200);
  parsed.message_body = String(parsed.message_body || '').slice(0, 2000);
  parsed.linkedin_connection_note = String(parsed.linkedin_connection_note || '').slice(0, 300);
  parsed.personalization_score = Math.min(5, Math.max(1, parseInt(parsed.personalization_score) || 3));
  parsed.personalization_notes = String(parsed.personalization_notes || '').slice(0, 500);

  var whatsappLink = '';
  if (buildData.channel === 'whatsapp') {
    var phone = lead.website_phone || lead.phone || '';
    var digits = phone.replace(/\D/g, '');
    if (digits.length >= 10) {
      whatsappLink = 'https://wa.me/' + digits + '?text=' + encodeURIComponent(parsed.message_body);
    }
  }

  return {
    json: {
      place_id: lead.place_id,
      profile_id: buildData.profile_id,
      channel: buildData.channel,
      tone: buildData.tone,
      subject_line: parsed.subject_line,
      message_body: parsed.message_body,
      linkedin_connection_note: parsed.linkedin_connection_note,
      whatsapp_link: whatsappLink,
      personalization_score: parsed.personalization_score,
      personalization_notes: parsed.personalization_notes,
      status: 'draft',
      model_used: modelUsed,
      _business_name: lead.business_name || '',
      _website: lead.website || '',
      _email: lead.email || '',
      _linkedin: lead.linkedin || lead.linkedin_profiles || ''
    }
  };
});

var allResults = $('Parse & Build Record').all().map(function(i) { return i.json; });
var successful = allResults.filter(function(r) { return r.model_used !== 'failed'; });
var failed = allResults.filter(function(r) { return r.model_used === 'failed'; });

return [{
  json: {
    success: true,
    total_processed: allResults.length,
    messages_generated: successful.length,
    failed_count: failed.length,
    channel: allResults[0] ? allResults[0].channel : null,
    tone: allResults[0] ? allResults[0].tone : null,
    messages: allResults.map(function(r) {
      return {
        place_id: r.place_id,
        business_name: r._business_name,
        channel: r.channel,
        personalization_score: r.personalization_score,
        subject_line: r.subject_line,
        message_body: r.message_body,
        linkedin_connection_note: r.linkedin_connection_note,
        whatsapp_link: r.whatsapp_link,
        model_used: r.model_used,
        email: r._email,
        website: r._website,
        linkedin: r._linkedin
      };
    })
  }
}];

// [DORMANT] Splits outreach summary into one item per email lead
// Enable this node + Gmail Send (Dormant) when ready to send
var data = $input.first().json;
var emailMessages = (data.messages || []).filter(function(m) {
  return m.channel === 'email' && m.email && m.model_used !== 'failed';
});
return emailMessages.map(function(m) {
  return {
    json: {
      to: m.email,
      subject: m.subject_line || 'Following up from OyeLabs',
      body: m.message_body,
      business_name: m.business_name,
      place_id: m.place_id
    }
  };
});
